func (o *Location) Preload(name string, retrieved any) error {
	if o == nil {
		return nil
	}

	switch name {
	case "JoinLocationCustomers":
		rels, ok := retrieved.(CustomerSlice)
		if !ok {
			return fmt.Errorf("location cannot load %T as %q", retrieved, name)
		}

		o.R.JoinLocationCustomers = rels

		for _, rel := range rels {
			if rel != nil {
				rel.R.JoinLocationLocation = o
			}
		}
		return nil
	case "LastLocationCustomers":
		rels, ok := retrieved.(CustomerSlice)
		if !ok {
			return fmt.Errorf("location cannot load %T as %q", retrieved, name)
		}

		o.R.LastLocationCustomers = rels

		for _, rel := range rels {
			if rel != nil {
				rel.R.LastLocationLocation = o
			}
		}
		return nil
	case "Orders":
		rels, ok := retrieved.(OrderSlice)
		if !ok {
			return fmt.Errorf("location cannot load %T as %q", retrieved, name)
		}

		o.R.Orders = rels

		for _, rel := range rels {
			if rel != nil {
				rel.R.Location = o
			}
		}
		return nil
	default:
		return fmt.Errorf("location has no relationship %q", name)
	}
}

