// LoadJoinLocationCustomers loads the location's JoinLocationCustomers into the .R struct
func (o *Location) LoadJoinLocationCustomers(ctx context.Context, exec bob.Executor, mods ...bob.Mod[*dialect.SelectQuery]) error {
	if o == nil {
		return nil
	}

	// Reset the relationship
	o.R.JoinLocationCustomers = nil

	related, err := o.JoinLocationCustomers(mods...).All(ctx, exec)
	if err != nil {
		return err
	}

	for _, rel := range related {
		rel.R.JoinLocationLocation = o
	}

	o.R.JoinLocationCustomers = related
	return nil
}

// LoadJoinLocationCustomers loads the location's JoinLocationCustomers into the .R struct
func (os LocationSlice) LoadJoinLocationCustomers(ctx context.Context, exec bob.Executor, mods ...bob.Mod[*dialect.SelectQuery]) error {
	if len(os) == 0 {
		return nil
	}

	customers, err := os.JoinLocationCustomers(mods...).All(ctx, exec)
	if err != nil {
		return err
	}

	for _, o := range os {
		if o == nil {
			continue
		}

		o.R.JoinLocationCustomers = nil
	}

	for _, o := range os {
		if o == nil {
			continue
		}

		for _, rel := range customers {

			if !rel.JoinLocationID.IsValue() {
				continue
			}
			if !(rel.JoinLocationID.IsValue() && o.ID == rel.JoinLocationID.MustGet()) {
				continue
			}

			rel.R.JoinLocationLocation = o

			o.R.JoinLocationCustomers = append(o.R.JoinLocationCustomers, rel)
		}
	}

	return nil
}

