type locationJoins[Q dialect.Joinable] struct {
	typ                   string
	JoinLocationCustomers modAs[Q, customerColumns]
	LastLocationCustomers modAs[Q, customerColumns]
	Orders                modAs[Q, orderColumns]
}

func (j locationJoins[Q]) aliasedAs(alias string) locationJoins[Q] {
	return buildLocationJoins[Q](buildLocationColumns(alias), j.typ)
}

func buildLocationJoins[Q dialect.Joinable](cols locationColumns, typ string) locationJoins[Q] {
	return locationJoins[Q]{
		typ: typ,
		JoinLocationCustomers: modAs[Q, customerColumns]{
			c: Customers.Columns,
			f: func(to customerColumns) bob.Mod[Q] {
				mods := make(mods.QueryMods[Q], 0, 1)

				{
					mods = append(mods, dialect.Join[Q](typ, Customers.Name().As(to.Alias())).On(
						to.JoinLocationID.EQ(cols.ID),
					))
				}

				return mods
			},
		},
		LastLocationCustomers: modAs[Q, customerColumns]{
			c: Customers.Columns,
			f: func(to customerColumns) bob.Mod[Q] {
				mods := make(mods.QueryMods[Q], 0, 1)

				{
					mods = append(mods, dialect.Join[Q](typ, Customers.Name().As(to.Alias())).On(
						to.LastLocationID.EQ(cols.ID),
					))
				}

				return mods
			},
		},
		Orders: modAs[Q, orderColumns]{
			c: Orders.Columns,
			f: func(to orderColumns) bob.Mod[Q] {
				mods := make(mods.QueryMods[Q], 0, 1)

				{
					mods = append(mods, dialect.Join[Q](typ, Orders.Name().As(to.Alias())).On(
						to.LocationID.EQ(cols.ID),
					))
				}

				return mods
			},
		},
	}
}
